    let currentAttempt = 1;
    currentAttempt <= ruleset.maxAttempts;
    currentAttempt++
  ) {

    for (let i = 0; i < players.length; i++) {

      let throwResult = throwDice(
        ruleset.diceNumber,
        ruleset.diceNumber * 6
      );

      players[i].points += throwResult;

      console.log(
        players[i].name +
        ' выбросил ' +
        players[i].points
      );
    }
  }

  return players;
};

